import{_ as o,o as a,c as t,ag as r}from"./chunks/framework.CvgP6Fyv.js";const h=JSON.parse('{"title":"Create Your Account","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/create-account.md","filePath":"getting-started/create-account.md"}'),n={name:"getting-started/create-account.md"};function i(s,e,c,l,u,d){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="create-your-account" tabindex="-1">Create Your Account <a class="header-anchor" href="#create-your-account" aria-label="Permalink to &quot;Create Your Account&quot;">​</a></h1><p>Getting started with MyCompanyDesk takes just a few minutes.</p><h2 id="sign-up" tabindex="-1">Sign up <a class="header-anchor" href="#sign-up" aria-label="Permalink to &quot;Sign up&quot;">​</a></h2><ol><li>Go to <a href="https://app.mycompanydesk.com" target="_blank" rel="noreferrer">app.mycompanydesk.com</a> and click <strong>Sign Up</strong></li><li>Choose one of the following methods: <ul><li><strong>Email and password</strong> — Enter your name, email, and a secure password</li><li><strong>Google</strong> — Sign in with your Google account</li><li><strong>Microsoft/Outlook</strong> — Sign in with your Microsoft account</li></ul></li><li>If you signed up with email, check your inbox for a <strong>verification email</strong> and click the link to verify your account</li></ol><h2 id="create-or-join-a-workspace" tabindex="-1">Create or join a workspace <a class="header-anchor" href="#create-or-join-a-workspace" aria-label="Permalink to &quot;Create or join a workspace&quot;">​</a></h2><p>After signing up, you have two options:</p><h3 id="create-a-new-workspace" tabindex="-1">Create a new workspace <a class="header-anchor" href="#create-a-new-workspace" aria-label="Permalink to &quot;Create a new workspace&quot;">​</a></h3><p>If you&#39;re the first person from your company, create a new workspace:</p><ol><li>Enter your <strong>company name</strong></li><li>Choose your preferred <strong>language</strong></li><li>Click <strong>Create Workspace</strong></li></ol><p>This creates a fresh workspace where you can start adding your company information, customers, and invoices.</p><h3 id="join-an-existing-workspace" tabindex="-1">Join an existing workspace <a class="header-anchor" href="#join-an-existing-workspace" aria-label="Permalink to &quot;Join an existing workspace&quot;">​</a></h3><p>If a colleague has already set up a workspace:</p><ol><li>Ask them to send you an <strong>invitation</strong> from Settings &gt; Team</li><li>Click the invitation link in your email</li><li>Accept the invitation to join their workspace</li></ol><p>You can be a member of multiple workspaces and switch between them from your account menu.</p><h2 id="choose-your-dashboard-profile" tabindex="-1">Choose your dashboard profile <a class="header-anchor" href="#choose-your-dashboard-profile" aria-label="Permalink to &quot;Choose your dashboard profile&quot;">​</a></h2><p>On first login, you&#39;ll see the <strong>onboarding card</strong> on your dashboard. MyCompanyDesk offers dashboard profiles tailored to different roles:</p><ul><li><strong>Owner / Director</strong> — High-level financial overview and cash flow</li><li><strong>Bookkeeper / Accountant</strong> — VAT compliance, audit trails, period locks</li><li><strong>Freelancer</strong> — Simplified view focused on invoicing and income</li><li><strong>Project-based</strong> — Project profitability and time tracking focus</li><li><strong>AR (Invoicing)</strong> — Invoice metrics and payment tracking</li><li><strong>AP (Purchasing)</strong> — Expense tracking and vendor management</li><li><strong>VAT Compliance</strong> — VAT calculations and deadlines</li><li><strong>Growth / Operations</strong> — Revenue trends and customer acquisition</li></ul><p>You can change your dashboard profile at any time from the dashboard settings.</p><h2 id="complete-the-onboarding-checklist" tabindex="-1">Complete the onboarding checklist <a class="header-anchor" href="#complete-the-onboarding-checklist" aria-label="Permalink to &quot;Complete the onboarding checklist&quot;">​</a></h2><p>The onboarding card guides you through three key setup steps:</p><ol><li><strong>Set up your company information</strong> — Add your business name, address, VAT number, and bank details</li><li><strong>Add your first customer</strong> — Create a customer record to start invoicing</li><li><strong>Create your first invoice</strong> — Send your first professional invoice</li></ol><p>The card disappears automatically once you complete these steps, or you can dismiss it manually.</p><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><p>Now that your account is ready, <a href="/getting-started/company-setup">set up your company information</a>.</p>',24)])])}const g=o(n,[["render",i]]);export{h as __pageData,g as default};
